const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/normalize`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': String($execution.id ?? Date.now()) }, body: JSON.stringify({ source: $json.source, payload: $json.payload }) });
const body = await response.json();
return [{ json: { run_id: String($execution.id ?? Date.now()), lead: body.data, original_payload: $json.payload } }];

const lead = $json.lead;
const rawKey = [lead.email ?? '', lead.phone ?? '', lead.company ?? '', lead.free_text_summary ?? ''].join('|').toLowerCase();
return [{ json: { ...$json, submission_key: Buffer.from(rawKey).toString('base64url') } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/idempotency/check`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ key: $json.submission_key, lead: $json.lead }) });
const body = await response.json();
return [{ json: { ...$json, idempotency: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const query = new URLSearchParams();
if ($json.lead.email) query.set('email', $json.lead.email);
if ($json.lead.phone) query.set('phone', $json.lead.phone);
const suffix = query.toString() ? `?${query.toString()}` : '';
const response = await fetch(`${baseUrl}/leads${suffix}`, { headers: { 'x-run-id': $json.run_id } });
const body = await response.json();
return [{ json: { ...$json, duplicate_matches: body.data ?? [] } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/llm/extract`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead: $json.lead }) });
const body = await response.json();
return [{ json: { ...$json, extraction: body.data, extraction_meta: { mode: body.mode, fallback_used: body.fallback_used, provider: body.provider, error: body.error } } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/llm/score`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead: $json.lead, extraction: $json.extraction }) });
const body = await response.json();
return [{ json: { ...$json, scoring: body.data, scoring_meta: { mode: body.mode, fallback_used: body.fallback_used, provider: body.provider, error: body.error } } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/rules/evaluate`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead: $json.lead, extraction: $json.extraction, scoring: $json.scoring, duplicate_match_count: ($json.duplicate_matches ?? []).length, duplicate_submission: $json.idempotency?.duplicate_submission ?? false }) });
const body = await response.json();
return [{ json: { ...$json, evaluation: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/leads/upsert`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead: $json.lead, extraction: $json.extraction, scoring: $json.scoring, evaluation: $json.evaluation }) });
const body = await response.json();
return [{ json: { ...$json, crm: body.data, lead_record: body.data.record } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
await fetch(`${baseUrl}/internal/slack/notify`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead_id: $json.lead_record.id, kind: 'hot_lead_sales' }) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
await fetch(`${baseUrl}/internal/slack/notify`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead_id: $json.lead_record.id, kind: 'manual_review' }) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/approvals/request`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead_id: $json.lead_record.id }) });
const body = await response.json();
return [{ json: { ...$json, approval: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
await fetch(`${baseUrl}/internal/slack/notify`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead_id: $json.lead_record.id, kind: 'approval_required' }) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const event = { event_id: `audit_${$json.run_id}_pending`, run_id: $json.run_id, event_type: 'approval_pending', timestamp: new Date().toISOString(), lead_id: $json.lead_record.id, route: $json.lead_record.route, status: 'awaiting_approval', details: { approval_id: $json.approval.approval_id, lead_score: $json.lead_record.lead_score } };
await fetch(`${baseUrl}/internal/audit/log`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify(event) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/email/draft`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead_id: $json.lead_record.id }) });
const body = await response.json();
return [{ json: { ...$json, email_draft: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const payload = { lead_id: $json.lead_record.id, requested_slot: null, route: $json.lead_record.route, owner: $json.lead_record.owner, notes: 'Auto-created booking handoff from workflow.' };
const response = await fetch(`${baseUrl}/booking/handoff`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify(payload) });
const body = await response.json();
return [{ json: { ...$json, booking_handoff: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const event = { event_id: `audit_${$json.run_id}_completed`, run_id: $json.run_id, event_type: 'lead_processed', timestamp: new Date().toISOString(), lead_id: $json.lead_record.id, route: $json.lead_record.route, status: 'completed', details: { lead_score: $json.lead_record.lead_score, approval_required: $json.evaluation.requires_human_approval, reply_draft_created: Boolean($json.email_draft), booking_handoff_created: Boolean($json.booking_handoff) } };
await fetch(`${baseUrl}/internal/audit/log`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify(event) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const event = { event_id: `audit_${$json.run_id}_closed`, run_id: $json.run_id, event_type: 'lead_closed', timestamp: new Date().toISOString(), lead_id: $json.lead_record.id, route: $json.lead_record.route, status: 'rejected_or_spam', details: { lead_score: $json.lead_record.lead_score, risk_flags: $json.evaluation.risk_flags } };
await fetch(`${baseUrl}/internal/audit/log`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify(event) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const approvalId = $json.approval_id ?? $json.approvalId;
const decision = $json.decision;
const response = await fetch(`${baseUrl}/internal/approvals/resolve`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': String($execution.id ?? Date.now()) }, body: JSON.stringify({ approval_id: approvalId, decision }) });
const body = await response.json();
return [{ json: { run_id: String($execution.id ?? Date.now()), approval: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/leads/${$json.approval.lead_id}`, { headers: { 'x-run-id': $json.run_id } });
const body = await response.json();
return [{ json: { ...$json, lead_record: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/internal/email/draft`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify({ lead_id: $json.lead_record.id, draft: $json.approval.email_draft }) });
const body = await response.json();
return [{ json: { ...$json, email_draft: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const response = await fetch(`${baseUrl}/booking/handoff`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify($json.approval.booking_payload) });
const body = await response.json();
return [{ json: { ...$json, booking_handoff: body.data } }];

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const event = { event_id: `audit_${$json.run_id}_approval_completed`, run_id: $json.run_id, event_type: 'approval_completed', timestamp: new Date().toISOString(), lead_id: $json.lead_record.id, route: $json.lead_record.route, status: 'approved', details: { approval_id: $json.approval.approval_id, reply_draft_created: Boolean($json.email_draft), booking_handoff_created: Boolean($json.booking_handoff) } };
await fetch(`${baseUrl}/internal/audit/log`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify(event) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const event = { event_id: `audit_${$json.run_id}_approval_rejected`, run_id: $json.run_id, event_type: 'approval_closed', timestamp: new Date().toISOString(), lead_id: $json.approval.lead_id, route: $json.approval.route, status: 'rejected', details: { approval_id: $json.approval.approval_id } };
await fetch(`${baseUrl}/internal/audit/log`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': $json.run_id }, body: JSON.stringify(event) });
return items;

const baseUrl = $env.MOCK_CRM_BASE_URL || 'http://mock-api:3001';
const payload = { error_id: `err_${String($execution.id ?? Date.now())}`, run_id: String($execution.id ?? Date.now()), timestamp: new Date().toISOString(), stage: 'workflow_failure', message: $json.error?.message ?? 'Workflow execution failed', details: $json };
await fetch(`${baseUrl}/internal/errors/log`, { method: 'POST', headers: { 'Content-Type': 'application/json', 'x-run-id': payload.run_id }, body: JSON.stringify(payload) });
return items;
